CREATE TABLE `buildings` (`id` INT UNSIGNED NOT NULL AUTO_INCREMENT,`building_no` VARCHAR(20) NOT NULL,`building_name` VARCHAR(100) NULL,`floor_count` INT NOT NULL,`sort_order` INT NOT NULL DEFAULT 0,`status` ENUM('ACTIVE','DISABLED') NOT NULL DEFAULT 'ACTIVE',`remark` VARCHAR(500) NULL,PRIMARY KEY (`id`),UNIQUE KEY `buildings_building_no_key` (`building_no`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `rooms` (`id` INT UNSIGNED NOT NULL AUTO_INCREMENT,`building_id` INT UNSIGNED NOT NULL,`house_no` VARCHAR(30) NOT NULL,`full_house_no` VARCHAR(60) NOT NULL,`floor_no` INT NOT NULL,`room_type` ENUM('RESIDENTIAL','SHOP') NOT NULL DEFAULT 'RESIDENTIAL',`area` DECIMAL(10,2) NULL,`decoration_status` ENUM('RENOVATED','UNRENOVATED','RENOVATING','UNKNOWN') NOT NULL DEFAULT 'UNKNOWN',`usage_type` ENUM('RESIDENCE','SHOP','OFFICE','STORAGE','OTHER') NOT NULL,`room_status` ENUM('EMPTY','PENDING_MOVE_IN','RENTED','PENDING_CHECKOUT','MAINTENANCE','FOR_SALE','SOLD','DISABLED','OTHER') NOT NULL DEFAULT 'EMPTY',`status_changed_at` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),`owner_name` VARCHAR(100) NULL,`owner_phone` VARCHAR(30) NULL,`owner_remark` VARCHAR(500) NULL,`remark` VARCHAR(500) NULL,`deleted_at` DATETIME(3) NULL,PRIMARY KEY (`id`),UNIQUE KEY `rooms_building_id_house_no_key` (`building_id`,`house_no`),KEY `rooms_building_floor_house_idx` (`building_id`,`floor_no`,`house_no`),CONSTRAINT `rooms_building_id_fkey` FOREIGN KEY (`building_id`) REFERENCES `buildings`(`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `room_status_histories` (`id` INT UNSIGNED NOT NULL AUTO_INCREMENT,`room_id` INT UNSIGNED NOT NULL,`from_status` ENUM('EMPTY','PENDING_MOVE_IN','RENTED','PENDING_CHECKOUT','MAINTENANCE','FOR_SALE','SOLD','DISABLED','OTHER') NULL,`to_status` ENUM('EMPTY','PENDING_MOVE_IN','RENTED','PENDING_CHECKOUT','MAINTENANCE','FOR_SALE','SOLD','DISABLED','OTHER') NOT NULL,`change_reason` VARCHAR(500) NULL,`business_type` VARCHAR(50) NULL,`business_id` INT UNSIGNED NULL,`changed_at` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),`changed_by` INT UNSIGNED NULL,PRIMARY KEY (`id`),KEY `room_status_histories_room_changed_idx` (`room_id`,`changed_at`),CONSTRAINT `room_status_histories_room_id_fkey` FOREIGN KEY (`room_id`) REFERENCES `rooms`(`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
